INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e49d41a8-8894-4890-82ce-f7d7fcd10985',
  '00000000-0000-0000-0000-000000000001',
  $escape$tcp_ip: Mastering the Three-Way Handshake and Beyond$escape$,
  $escape$When a client initiates a connection with a server using tcp_ip, it sends a SYN packet, which is acknowledged by the server with a SYN-ACK packet. The client then sends an ACK packet, completing the three-way handshake. Flow control is achieved through the use of TCP window sizes, which dictate the amount of data that can be sent before an acknowledgement is required. Congestion control, on the other hand, is managed through mechanisms like slow-start and congestion avoidance algorithms. TIME_WAIT is a state where a connection remains active for a short period after it's been closed, to allow for duplicate ACKs and retransmissions.$escape$,
  NULL,
  NULL,
