INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '35612ec9-09f4-4f24-a6bd-6e0c9f8a9dcd',
  '00000000-0000-0000-0000-000000000001',
  $escape$tcp_ip Service Mesh with Sidecar Proxies and mTLS$escape$,
  $escape$A service mesh uses sidecar proxies to intercept and manage communication between microservices. In tcp_ip, this is achieved using the SO_MARK and SO_ATTACH_FILTER socket options. The sidecar proxy uses the TCP_ESTATS socket option to expose detailed connection statistics. Mutual Transport Layer Security (mTLS) is enabled using the TLS handshake protocol. Observability is enhanced by logging and metrics collected by the sidecar proxy. The service mesh controller ensures sidecar proxies are properly configured and communication between services is secure.$escape$,
  $escape$['import net', 'from netfilter_queue import NFQ_CB_ACCEPT, NFQ_CB_DISCARD', 'import socket', 'import ssl', 'sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)', "sock.bind(('localhost', 8080))", 'sock.listen(5)', 'while True:', '    conn, addr = sock.accept()', '    ssl_context = ssl.create_default_context(ssl.Purpose.SERVER_AUTH)', "    ssl_context.load_cert_chain('server.crt', 'server.key')", '    ssl_conn = ssl_context.wrap_socket(conn, server_side=True)', '    data = ssl_conn.recv(1024)', '    ssl_conn.sendall(data)']$escape$,
  $escape$python$escape$,
