INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a4154787-c04a-4cdc-90d0-08549db88f64',
  '00000000-0000-0000-0000-000000000001',
  $escape$tcp_ip — IPv4 vs IPv6: Choosing the Right IP Version$escape$,
  $escape$When working with tcp_ip, you'll encounter both IPv4 and IPv6. IPv4 uses 32-bit addresses, while IPv6 uses 128-bit addresses. To choose between them, consider your network size and address space requirements. IPv4 is sufficient for small to medium-sized networks, but IPv6 is necessary for larger networks or those with a high address space demand. Subnetting is used to divide IP addresses into smaller sub-networks, improving routing efficiency. CIDR notation (e.g., /24) specifies the number of bits allocated to the subnet mask. NAT (Network Address Translation) is used to map multiple private IP addresses to a single public IP address. When choosing between IPv4 and IPv6, consider the trade-offs between address space, routing efficiency, and NAT requirements.$escape$,
  NULL,
  NULL,
